const body = $input.item.json.body || $input.item.json;
const text = body.message?.text || '';
const chatId = body.message?.chat?.id;
const userId = body.message?.from?.id;

let command = 'help';
let arg = '';

if (text.startsWith('/listar') || text.startsWith('/citas')) {
  command = 'listar';
  arg = text.split(' ').slice(1).join(' ').trim();
} else if (text.startsWith('/cancelar')) {
  command = 'cancelar';
  arg = text.split(' ').slice(1).join(' ').trim();
}

return {
  json: { command, arg, chatId, userId, originalText: text }
};

const items = $input.all().map(i => i.json);
const chatId = items[0]?.chatId || $('Parse Command').first().json.chatId;
const arg = $('Parse Command').first().json.arg || '';

if (items.length === 0 || !items[0].numero_cita) {
  return [{ json: { chatId, text: `❌ No se encontraron citas activas${arg ? ` para: "${arg}"` : '.'}` } }];
}

let msg = `🏥 *Citas médicas encontradas:*\n\n`;
items.forEach(c => {
  msg += `🆔 *${c.numero_cita}* (${c.estado.toUpperCase()})\n`;
  msg += `👤 ${c.paciente_nombre}\n`;
  msg += `📅 ${c.fecha_cita} | ${c.hora_cita ? c.hora_cita.substring(0,5) : ''}\n`;
  msg += `📋 ${c.especialidad} - ${c.doctor || 'Sin asignar'}\n\n`;
});
msg += `Para cancelar:\n\`/cancelar <numero_cita>\``;

return [{ json: { chatId, text: msg } }];

const items = $input.all().map(i => i.json);
const chatId = $('Parse Command').first().json.chatId;
const arg = $('Parse Command').first().json.arg || '';

if (items.length === 0 || !items[0].numero_cita) {
  return [{ json: { chatId, success: false, text: `❌ No se encontró cita activa con número *${arg}*.\nVerifica el número e intenta de nuevo.` } }];
}

const cita = items[0];
return [{ json: { ...cita, chatId, success: true, text: `✅ Cita *${cita.numero_cita}* cancelada exitosamente.\n\n👤 ${cita.paciente_nombre}\n📋 ${cita.especialidad}\n📅 ${cita.fecha_cita} | ${cita.hora_cita ? cita.hora_cita.substring(0,5) : ''}` } }];

const chatId = $('Parse Command').first().json.chatId;
const text = `👋 *¡Hola! Bienvenido al asistente de Clínica Local.*

Comandos disponibles:

📅 *Ver Citas:*
\`/listar\` - Todas las citas
\`/listar <nombre o teléfono>\` - Filtrar

❌ *Cancelar Cita:*
\`/cancelar <numero_cita>\``;
return [{ json: { chatId, text } }];
